import React, { useState, useEffect } from 'react';
import {
  TextField,
  Button,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Box,
  Grid,
  Typography,
} from '@mui/material';
import { createProductType, updateProductType } from '../services/api';

const categoryOptions = ['Asset', 'Consumable'];
const assetTypeOptions = ['Asset', 'Consumable', 'Component'];
const assetCategoryTypeOptions = ['IT', 'Non IT'];

const ProductTypeForm = ({ editing, onSave, onClose, productTypes }) => {
  const [formData, setFormData] = useState({
    display_name: '',
    api_name: '',
    display_plural_name: '',
    api_plural_name: '',
    category: '',
    parent_product_type: '',
    asset_type: '',
    asset_category_type: '',
    description: '',
  });

  useEffect(() => {
    if (editing) {
      setFormData(editing);
    } else {
      setFormData({
        display_name: '',
        api_name: '',
        display_plural_name: '',
        api_plural_name: '',
        category: '',
        parent_product_type: '',
        asset_type: '',
        asset_category_type: '',
        description: '',
      });
    }
  }, [editing]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    try {
      if (editing) {
        await updateProductType(editing.id, formData);
      } else {
        await createProductType(formData);
      }
      onSave();
    } catch (error) {
      console.error('Error saving product type:', error);
    }
  };

  return (
    <Box component="form" sx={{ mt: 2 }}>
      <Grid container spacing={2}>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label={<><Typography component="span" color="error">*</Typography> Display Name</>}
            name="display_name"
            value={formData.display_name}
            onChange={handleChange}
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label={<><Typography component="span" color="error">*</Typography> API Name</>}
            name="api_name"
            value={formData.api_name}
            onChange={handleChange}
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label={<><Typography component="span" color="error">*</Typography> Display Plural Name</>}
            name="display_plural_name"
            value={formData.display_plural_name}
            onChange={handleChange}
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label={<><Typography component="span" color="error">*</Typography> API Plural Name</>}
            name="api_plural_name"
            value={formData.api_plural_name}
            onChange={handleChange}
            margin="normal"
          />
        </Grid>

        <Grid item xs={12} sm={6}>
          <FormControl fullWidth margin="normal">
            <InputLabel>
              <><Typography component="span" color="error">*</Typography> Category</>
            </InputLabel>
            <Select
              displayEmpty
              name="category"
              value={formData.category}
              onChange={handleChange}
              renderValue={(selected) => selected || '-- Select Category --'}
            >
              {categoryOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth margin="normal">
            <InputLabel>
              <><Typography component="span" color="error">*</Typography> Parent Product Type</>
            </InputLabel>
            <Select
              displayEmpty
              name="parent_product_type"
              value={formData.parent_product_type}
              onChange={handleChange}
              renderValue={(selected) => selected || '-- Select Parent --'}
            >
              <MenuItem value="">
                <em>None</em>
              </MenuItem>
              {productTypes.map((pt) => (
                <MenuItem key={pt.id} value={pt.id}>
                  {pt.display_name}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>

        <Grid item xs={12} sm={6}>
          <FormControl fullWidth margin="normal">
            <InputLabel>
              <><Typography component="span" color="error">*</Typography> Asset Type</>
            </InputLabel>
            <Select
              displayEmpty
              name="asset_type"
              value={formData.asset_type}
              onChange={handleChange}
              renderValue={(selected) => selected || '-- Select Asset Type --'}
            >
              {assetTypeOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label="Description"
            name="description"
            value={formData.description}
            onChange={handleChange}
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth margin="normal">
            <InputLabel>Asset Category Type</InputLabel>
            <Select
              displayEmpty
              name="asset_category_type"
              value={formData.asset_category_type}
              onChange={handleChange}
              renderValue={(selected) => selected || '-- Select Asset Category --'}
            >
              {assetCategoryTypeOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>

        <Grid item xs={12}>
          <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end', gap: 1 }}>
            <Button variant="outlined" onClick={onClose}>
              Close
            </Button>
            <Button variant="contained" onClick={handleSave}>
              Save
            </Button>
          </Box>
        </Grid>
      </Grid>
    </Box>
  );
};

export default ProductTypeForm;
